class Solution(object):
    def splitArray(self, nums):
        n = len(nums)
        # Sieve of Eratosthenes
        is_prime = [False, False] + [True] * (n - 2) if n >= 2 else [False] * n
        for i in range(2, int(n**0.5) + 1):
            if is_prime[i]:
                for j in range(i * i, n, i):
                    is_prime[j] = False

        sum_a = sum(nums[i] for i in range(n) if is_prime[i])
        sum_b = sum(nums[i] for i in range(n) if not is_prime[i])
        return abs(sum_a - sum_b)
